#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template <typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template <typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=1e6+10,INF=0x3f3f3f3f;const LL INFll=4e18;int n,m;
namespace MaxFlow 
{
	int head[N],des[N<<1],nxt[N<<1],cgt=1,cap[N<<1],dep[N],que[N],H,T,s,t,f2[N];
	inline void ins(const int &x,const int &y,const int &w)
	{
		nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=w;
		nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;
	}
	inline bool bfs()
	{
		memset(dep,0,sizeof(dep));dep[que[H=T=1]=s]=1;int u;
		while(H<=T)grep(u=que[H++],i)if(cap[i]&&!dep[des[i]])dep[que[++T]=des[i]]=dep[u]+1;return dep[t];
	}
	inline int dfs(const int &u=s,int in=INF)
	{
		if(u==t)return in;int out=0;for(int &i=f2[u];i;i=nxt[i])
		{
			int v=des[i];if(cap[i]&&dep[v]==dep[u]+1)
			{
				int tmp=dfs(v,min(in,cap[i]));
				cap[i]-=tmp;cap[i^1]+=tmp;in-=tmp;out+=tmp;
			} if(!in)break;
		}
		if(!out)dep[u]=0;return out;
	}
	inline int dinic(const int &S,const int &T){s=S;t=T;int tmp=0;while(bfs())memcpy(f2,head,(n+m+3)<<2),tmp+=dfs();return tmp;}
}
using MaxFlow::dinic;using MaxFlow::ins;
int main()
{
	n=read(),m=read();rep(1,n,i)ins(i,n+m+2,read());int Pos=0;
	rep(1,m,i){ins(i+n,read(),INF);ins(i+n,read(),INF);int c=read();ins(n+m+1,i+n,c);Pos+=c;}
	printf("%d\n",Pos-dinic(n+m+1,n+m+2));return 0;
	
}
